content:
{
  "mode": "method",
  "tests": [
    {
      "name": "get_report_valid_id",
      "input": {
        "reportId": 1
      },
      "output": {
        "status": "success",
        "data": {
          "reportId": 1,
          "title": "Diagnostic Report 1",
          "content": "Detailed analysis of the diagnostic report."
        }
      },
      "notes": "Validates retrieval of a report with a valid ID."
    },
    {
      "name": "get_report_invalid_id",
      "input": {
        "reportId": 999
      },
      "output": {
        "status": "error",
        "message": "Report not found"
      },
      "notes": "Tests the API's response to a non-existent report ID."
    },
    {
      "name": "create_report_valid_data",
      "input": {
        "title": "New Diagnostic Report",
        "content": "Content of the new report."
      },
      "output": {
        "status": "success",
        "reportId": 2
      },
      "notes": "Validates creation of a new report with valid data."
    },
    {
      "name": "create_report_missing_title",
      "input": {
        "content": "Content without a title."
      },
      "output": {
        "status": "error",
        "message": "Title is required"
      },
      "notes": "Tests the API's validation for missing required fields."
    },
    {
      "name": "update_report_valid_data",
      "input": {
        "reportId": 1,
        "title": "Updated Report Title",
        "content": "Updated content of the report."
      },
      "output": {
        "status": "success",
        "message": "Report updated successfully"
      },
      "notes": "Validates updating an existing report."
    },
    {
      "name": "update_report_invalid_id",
      "input": {
        "reportId": 999,
        "title": "Invalid Update",
        "content": "Trying to update a non-existent report."
      },
      "output": {
        "status": "error",
        "message": "Report not found"
      },
      "notes": "Tests the API's response to updating a non-existent report."
    },
    {
      "name": "delete_report_valid_id",
      "input": {
        "reportId": 1
      },
      "output": {
        "status": "success",
        "message": "Report deleted successfully"
      },
      "notes": "Validates deletion of a report with a valid ID."
    },
    {
      "name": "delete_report_invalid_id",
      "input": {
        "reportId": 999
      },
      "output": {
        "status": "error",
        "message": "Report not found"
      },
      "notes": "Tests the API's response to deletion of a non-existent report."
    }
  ],
  "assumptions": "All report IDs are integers and start from 1. Database is pre-populated with test data.",
  "notes": "Ensure that the database is in a clean state before running tests."
}
